interface ITheme {
  name: string;
  hexCode: string;
}

abstract class Theme implements ITheme {
  constructor(public name: string, public hexCode: string) {}

  abstract applyTheme(): void;

  getThemeInfo(): string {
    return `Theme Name: ${this.name}, Hex Code: ${this.hexCode}`;
  }
}

class LightTheme extends Theme {
  constructor() {
    super("Light Theme", "#FFFFFF");
  }

  override applyTheme(): void {
    console.log(`Applying Light Theme: ${this.getThemeInfo()}`);
  }
};

class DarkTheme extends Theme {
  constructor(){
    super("Dark Theme", "#333333");
  }

  override applyTheme(): void {
    console.log(`Applying Dark Theme: ${this.getThemeInfo()}`);
  }
};

class HighContrastTheme extends Theme {
  constructor(){
    super("High Contrast Theme", "#000000");
  }

  override applyTheme(): void {
    console.log(`Applying High Contrast Theme: ${this.getThemeInfo()}`);
  }
};

class NeonTheme extends Theme {
  constructor() {
    super("Neon Theme", "#39FF14");
  }

  override applyTheme(): void {
    console.log(`Applying Neon Theme: ${this.getThemeInfo()}`);
  }
}

enum ThemeType {
  Light = "light",
  Dark = "dark",
  HighContrast = "highcontrast",
  Neon = "neon"
}

// function to create themes based on user preference
function createTheme(themeType: keyof typeof ThemeType): Theme {
  switch (themeType) {
    case "Light":
      return new LightTheme();
    case "Dark":
      return new DarkTheme();
    case "HighContrast":
      return new HighContrastTheme();
    case "Neon":
      return new NeonTheme();
    default:
      throw new Error('Invalid theme type');
  }
}

interface IButton {
  label: string;
  onClick(): void;
};

class Button implements IButton {
  constructor(public label: string, public onClick: () => void) {}

  click(): void {
    this.onClick();
    console.log(`Button "${this.label}" clicked.`);
  }
};

class ThemeButton extends Button {
  constructor(label: string, onClick: () => void, private theme: Theme) {
    super(label, onClick);
  }

  override click(): void {
    super.click();
    this.theme.applyTheme();
  }
};

class ButtonFactory {
  static createButton(btnInfo: { label: string; onClick: () => void }, selectedTheme: keyof typeof ThemeType): ThemeButton {
    const theme = createTheme(selectedTheme);
    return new ThemeButton(btnInfo.label, btnInfo.onClick, theme);
  }
};

// Example usage:
const lightButton = ButtonFactory.createButton(
  { 
    label: "Light Mode", 
    onClick: () => console.log("Light Mode Activated") 
  }, 
  "Light");

const darkButton = ButtonFactory.createButton(
  { 
    label: "Dark Mode", 
    onClick: () => console.log("Dark Mode Activated") 
  }, 
  "Dark");

const highContrastButton = ButtonFactory.createButton(
  { 
    label: "High Contrast Mode", 
    onClick: () => console.log("High Contrast Mode Activated") 
  }, 
  "HighContrast");

const neonButton = ButtonFactory.createButton(
  { 
    label: "Neon Mode", 
    onClick: () => console.log("Neon Mode Activated") 
  }, 
  "Neon");

lightButton.click();
darkButton.click();
highContrastButton.click();
neonButton.click();

type TInputData = string;

interface IDataStrategy {
  retrieveData(): TInputData;
  storeData(data: TInputData): void;
};

class InMemoryStrategy implements IDataStrategy {
  private data: TInputData = '';
  private static instance: InMemoryStrategy;
  constructor () {
    if (!InMemoryStrategy.instance) {
      InMemoryStrategy.instance = this;
    }

    return InMemoryStrategy.instance;
  };

  retrieveData(): TInputData {
    console.log('Retrieving data from in-memory storage.');
    return this.data;
  }

  storeData(data: TInputData): void {
    console.log('Storing data in in-memory storage.');
    this.data = data;
  }
};

class DatabaseStrategy implements IDataStrategy {
  private data: TInputData = '';
  private static instance: DatabaseStrategy;
  constructor () {
    if (!DatabaseStrategy.instance) {
      DatabaseStrategy.instance = this;
    }

    return DatabaseStrategy.instance;
  };

  retrieveData(): TInputData {
    console.log('Retrieving data from database.');
    return this.data;
  };

  storeData(data: TInputData): void {
    console.log('Storing data in database.');
    this.data = data;
  };
};

class APIStrategy implements IDataStrategy {
  private data: TInputData = '';
  private static instance: APIStrategy;
  constructor () {
    if (!APIStrategy.instance) {
      APIStrategy.instance = new APIStrategy();
    }

    return APIStrategy.instance;
  };

  retrieveData(): TInputData {
    console.log('Retrieving data from external API.');
    return this.data;
  };

  storeData(data: TInputData): void {
    console.log('Storing data to external API.');
    this.data = data;
  };
};

class CloudStrategy implements IDataStrategy {
  private data: TInputData = '';
  private static instance: CloudStrategy;

  constructor () {
    if (!CloudStrategy.instance) {
      CloudStrategy.instance = new CloudStrategy();
    }

    return CloudStrategy.instance;
  };

  retrieveData(): TInputData {
    console.log('Retrieving data from cloud storage.');
    return this.data;
  };

  storeData(data: TInputData): void {
    console.log('Storing data in cloud storage.');
    this.data = data;
  };
};

const strategyConfig = {
  inMemory: new InMemoryStrategy(),
  database: new DatabaseStrategy(),
  api: new APIStrategy(),
  cloud: new CloudStrategy()
};

type TStrategyType = keyof typeof strategyConfig;

class DataRepository {
  private strategy: TStrategyType;

  checkStrategy(strategy: TStrategyType): void {
    if (!strategyConfig[strategy]) {
      throw new Error(`Strategy ${strategy} is not supported.`);
    }
  };

  constructor(strategy: TStrategyType) {
    this.checkStrategy(strategy);
    this.strategy = strategy;
  };

  setStrategy(strategy: TStrategyType): void {
    this.checkStrategy(strategy);
    this.strategy = strategy;
  };

  retrieveData(): TInputData {
    return strategyConfig[this.strategy].retrieveData();
  };
};

// Client code
const inMemoryRepo = new DataRepository("inMemory");
const databaseRepo = new DataRepository("database");
const apiRepo = new DataRepository("api");
const cloudRepo = new DataRepository("cloud");

inMemoryRepo.retrieveData();
databaseRepo.retrieveData();
apiRepo.retrieveData();
cloudRepo.retrieveData();

interface Exporter {
  exportContent(content: string): string;
}

interface IReport {
  generate(): string;
  setExporter(exporter: Exporter): void;
}

abstract class Report implements IReport {
  constructor(protected exporter: Exporter) {}

  generate(): string {
    const content = this.buildContent();
    return this.exporter.exportContent(content);
  }

  setExporter(exporter: Exporter): void {
    this.exporter = exporter;
  }

  protected abstract buildContent(): string;
}

class SummaryReport extends Report {
  protected buildContent(): string {
    return "Summary Report Content";
  }
}

class DetailedReport extends Report {
  protected buildContent(): string {
    return "Detailed Report Content";
  }
}

class HtmlExporter implements Exporter {
  exportContent(content: string): string {
    return `<html><body><h1>${content}</h1></body></html>`;
  }
}

class PdfExporter implements Exporter {
  exportContent(content: string): string {
    return `PDF Format: ${content}`;
  }
}

// Bridge avoids subclass explosion when reports and exporters multiply.

// Example usage:
const htmlExporter = new HtmlExporter();
const pdfExporter = new PdfExporter();

const summaryReport = new SummaryReport(htmlExporter);
console.log(summaryReport.generate());

summaryReport.setExporter(pdfExporter);
console.log(summaryReport.generate());

const detailedReport = new DetailedReport(pdfExporter);
console.log(detailedReport.generate());

// Exercise 04 Answer: OmniContent strategic design

/*
Modules (exactly 8) with classification and justification

1) Content Ingestion - Deep Module
   Responsibility: Normalize and validate incoming content from any source.
   Justification: Small interface (ingest/subscribe) hides complex parsing,
   validation, enrichment, and error handling pipelines.

2) Access Control - Deep Module
   Responsibility: Enforce permissions across front-ends and partner APIs.
   Justification: Simple canAccess interface hides complex policy evaluation
   (RBAC, ABAC, subscription tiers).

3) Metadata Management - Deep Module
   Responsibility: Store, index, and evolve content metadata.
   Justification: Simple CRUD/query interface hides schema evolution, migration,
   and storage optimizations.

4) Analytics - Deep Module
   Responsibility: Collect events, aggregate metrics, and produce reports.
   Justification: Simple track/report interface hides aggregation, batching,
   and anomaly handling.

5) Notification System - Deep Module
   Responsibility: Route notifications across channels with templates and rules.
   Justification: Simple send interface hides routing, throttling, and delivery
   guarantees.

6) Search - Shallow Module
   Responsibility: Provide search API over content.
   Justification: Interface closely matches functionality; delegates heavy work
   to ingestion updates and index engine.

7) Content Delivery - Shallow Module
   Responsibility: Deliver content to clients and partners.
   Justification: Facade interface maps directly to delivery endpoints and
   caching policies.

8) User Management - Shallow Module
   Responsibility: Account, auth, and profile management.
   Justification: Straightforward operations with limited hidden complexity.

Pattern requirements
 - Bridge: Access Control (abstraction) decoupled from implementations (RBAC/ABAC).
 - Factory: Content Ingestion creates processors for Article/Video/Audio.
 - Observer: Search subscribes to Content Ingestion to keep indexes fresh.
 - Repository: Metadata Management hides persistence details to avoid viscosity.

Strategic conclusion
This design combats rigidity by isolating change in deep modules and stable
interfaces, fragility by decoupling modules through patterns, immobility by
keeping policies and storage behind abstractions, and viscosity by minimizing
cross-module edits for schema or policy changes. The result is a long-term
platform that adapts to new content types and business models with low risk.
*/

// Shared domain types
export type ContentType = "article" | "video" | "podcast";

export interface ContentInput {
  type: ContentType;
  rawPayload: string;
  source: "cms" | "partner" | "upload";
}

export interface ContentRecord {
  id: string;
  type: ContentType;
  normalizedPayload: string;
  metadata: Record<string, string>;
}

// 1) Content Ingestion (Deep) + Factory Pattern + Observer Pattern
export interface ContentProcessor {
  process(input: ContentInput): ContentRecord;
}

export interface ArticleProcessor extends ContentProcessor {}
export interface VideoProcessor extends ContentProcessor {}
export interface AudioProcessor extends ContentProcessor {}

export interface ContentProcessorFactory {
  createProcessor(type: ContentType): ContentProcessor;
}

export interface ContentIngestionObserver {
  onContentIngested(record: ContentRecord): void;
}

export interface ContentIngestionModule {
  ingest(input: ContentInput): ContentRecord;
  subscribe(observer: ContentIngestionObserver): () => void;
}

// 2) Access Control (Deep) + Bridge Pattern
export interface AccessSubject {
  id: string;
  roles: string[];
  attributes: Record<string, string>;
}

export interface AccessResource {
  id: string;
  type: "content" | "metadata" | "analytics";
  attributes: Record<string, string>;
}

export type AccessAction = "read" | "write" | "delete" | "publish";

// Implementor side of the Bridge
export interface AccessControlImplementor {
  canAccess(subject: AccessSubject, action: AccessAction, resource: AccessResource): boolean;
}

// Abstraction side of the Bridge
export interface AccessControlModule {
  canAccess(subject: AccessSubject, action: AccessAction, resource: AccessResource): boolean;
  setImplementation(impl: AccessControlImplementor): void;
}

export interface RoleBasedAccessControl extends AccessControlImplementor {}
export interface AttributeBasedAccessControl extends AccessControlImplementor {}

// 3) Metadata Management (Deep) + Repository Pattern
export interface MetadataRecord {
  contentId: string;
  tags: string[];
  attributes: Record<string, string>;
}

export interface MetadataQuery {
  tag?: string;
  attributeKey?: string;
  attributeValue?: string;
}

export interface ContentMetadataRepository {
  findById(contentId: string): MetadataRecord | null;
  save(record: MetadataRecord): void;
  query(filter: MetadataQuery): MetadataRecord[];
}

export interface MetadataManagementModule {
  get(contentId: string): MetadataRecord | null;
  upsert(record: MetadataRecord): void;
  search(filter: MetadataQuery): MetadataRecord[];
}

// 4) Analytics (Deep)
export interface AnalyticsEvent {
  name: string;
  contentId?: string;
  attributes: Record<string, string>;
}

export interface AnalyticsQuery {
  name: string;
  from: string;
  to: string;
}

export interface AnalyticsReport {
  name: string;
  total: number;
}

export interface AnalyticsModule {
  track(event: AnalyticsEvent): void;
  report(query: AnalyticsQuery): AnalyticsReport;
}

// 5) Notification System (Deep)
export interface NotificationRequest {
  userId: string;
  channel: "email" | "sms" | "push";
  templateId: string;
  variables: Record<string, string>;
}

export interface NotificationResult {
  requestId: string;
  accepted: boolean;
}

export interface NotificationModule {
  send(request: NotificationRequest): NotificationResult;
}

// 6) Search (Shallow) + Observer subscription
export interface SearchQuery {
  text: string;
  type?: ContentType;
}

export interface SearchResult {
  contentId: string;
  score: number;
}

export interface SearchModule extends ContentIngestionObserver {
  query(request: SearchQuery): SearchResult[];
}

// 7) Content Delivery (Shallow)
export interface DeliveryRequest {
  contentId: string;
  channel: "web" | "mobile" | "partner";
}

export interface DeliveryResponse {
  contentId: string;
  payload: string;
}

export interface ContentDeliveryModule {
  deliver(request: DeliveryRequest): DeliveryResponse;
}

// 8) User Management (Shallow)
export interface UserProfile {
  id: string;
  email: string;
  displayName: string;
}

export interface UserManagementModule {
  register(email: string, password: string): UserProfile;
  authenticate(email: string, password: string): string;
  updateProfile(profile: UserProfile): UserProfile;
}

